import re

data_source = locals()['var_function-call-9534659010850852567']
if isinstance(data_source, str):
    with open(data_source, 'r') as f:
        data = json.load(f)
else:
    data = data_source

us_states = {
    'AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 
    'HI', 'ID', 'IL', 'IN', 'IA', 'KS', 'KY', 'LA', 'ME', 'MD', 
    'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 
    'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 
    'SD', 'TN', 'TX', 'UT', 'VT', 'VA', 'WA', 'WV', 'WI', 'WY', 'DC'
}

state_pattern = re.compile(r",\s([A-Z]{2}),\sthis")

businesses_by_state = {}

for entry in data:
    desc = entry.get('description', '')
    match = state_pattern.search(desc)
    if match:
        state = match.group(1)
        if state in us_states:
            if state not in businesses_by_state:
                businesses_by_state[state] = []
            businesses_by_state[state].append(entry['business_id'])

# Find top state
if not businesses_by_state:
    result = {"error": "No US businesses found"}
else:
    top_state = max(businesses_by_state, key=lambda k: len(businesses_by_state[k]))
    count = len(businesses_by_state[top_state])
    ids = businesses_by_state[top_state]

    # Convert ids for DuckDB (businessid_ -> businessref_)
    duckdb_ids = [bid.replace("businessid_", "businessref_") for bid in ids]

    result = {
        "top_state": top_state,
        "count": count,
        "business_refs": duckdb_ids
    }

print("__RESULT__:")
print(json.dumps(result))"}

